using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().HasIndex(p => p.Sku);
        modelBuilder.Entity<Product>().ToContainer("Products");
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        var entity = modelBuilder.Entity<Product>();
        entity.ToContainer("Products");

        // EF Core 9 changed discriminator from "Discriminator" to "$type".
        // Preserve the old name so existing 500K documents remain readable
        // and raw SQL queries referencing c.Discriminator keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "EntityType|Key" to just "Key".
        // Preserve the old format so existing documents are not orphaned.
        entity.HasPartitionKey(p => p.Id);
        entity.Property(p => p.Id)
              .HasConversion<string>()
              .ToJsonProperty("id");
        entity.Property(p => p.Id)
              .ValueGeneratedNever();

        // HasIndex is ignored by the Cosmos provider — removed to avoid
        // the warning/error EF Core 9 now raises for unsupported operations.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

